import{_ as e,o,c as a,a2 as r}from"./chunks/framework.D14Z5eOz.js";const p=JSON.parse('{"title":"What is sdd?","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/what-is-sdd.md","filePath":"concepts/what-is-sdd.md","lastUpdated":1784865624000}'),s={name:"concepts/what-is-sdd.md"};function i(d,t,n,l,c,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="what-is-sdd" tabindex="-1">What is sdd? <a class="header-anchor" href="#what-is-sdd" aria-label="Permalink to &quot;What is sdd?&quot;">​</a></h1><p><strong>Structured Vibe Coding (<code>sdd</code>)</strong> is a <strong>local Spec-Driven Development</strong> tool for software engineers.</p><p>It is a <strong>CLI process coach</strong> that lives in your application repository. It does not replace your stack (React, Java, Python, …). It adds:</p><ol><li><strong>Workflows</strong> — ordered stages (intent → design → tasks → implement → verify, or lighter/heavier packs)</li><li><strong>Change packs</strong> — a folder per unit of work under <code>changes/&lt;id&gt;/</code> with markdown specs and <code>meta.yaml</code></li><li><strong>AI agent wiring</strong> — thin stubs for <strong>one</strong> coding agent (Copilot, Grok, or Claude) plus a single playbook (<code>.sdd/protocol.md</code>)</li><li><strong>Local verify &amp; complete</strong> — check work on your machine, mark the change done in place</li></ol><h2 id="how-it-fits-together" tabindex="-1">How it fits together <a class="header-anchor" href="#how-it-fits-together" aria-label="Permalink to &quot;How it fits together&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piece</th><th>Role</th></tr></thead><tbody><tr><td><strong>You</strong></td><td>Decide scope, approve quality, run <code>sdd</code></td></tr><tr><td><strong><code>sdd</code> CLI</strong></td><td>Process state: stages, gates, handoff files</td></tr><tr><td><strong>AI coding agent</strong></td><td>Write/refine specs and product code</td></tr><tr><td><strong>Your editor</strong></td><td>Edit files (no special IDE extension required)</td></tr></tbody></table><h2 id="what-it-is-not" tabindex="-1">What it is not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What it is not&quot;">​</a></h2><ul><li>Not a required VS Code / IntelliJ extension</li><li>Not a hosted multi-tenant SaaS</li><li>Not a replacement for Jira/Git as your company system of record</li><li>Not “install every AI host at once” — you pick <strong>one</strong> at <code>sdd init</code></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./what-you-can-achieve">What you can achieve</a></li><li><a href="./../reference/workflows">Built-in workflows</a></li><li><a href="./../reference/agents">Available agents</a></li></ul>',10)])])}const u=e(s,[["render",i]]);export{p as __pageData,u as default};
